INSERT INTO episodes (title, episode_number, description, guest, duration, publish_date, cloudflare_url, spotify_url, apple_url, youtube_url, rumble_url, tags, featured) VALUES (' THE DREW GRIMALDI PODCAST - SPECIAL GUEST - Rick Weible', NULL, 'Utilizing his 30-year background in cybersecurity and network engineering, Weible focuses heavily on challenging the reliability of electronic voting infrastructure. In 2023, he founded USCASE.org, an organization dedicated to examining election security and pushing for a return to hand-counted paper ballots. He frequently travels across South Dakota, North Dakota, and Wyoming conducting training sessions for poll observers, analyzing machine accuracy testing, and alleging vulnerabilities in state tabulators. Weible has collaborated closely with prominent national figures in the movement, notably serving as a campaign manager for Mike Lindell.
INSERT INTO episodes (title, episode_number, description, guest, duration, publish_date, cloudflare_url, spotify_url, apple_url, youtube_url, rumble_url, tags, featured) VALUES ('THE DREW GRIMALDI PODCAST - SPECIAL GUEST - Dr. Rick Addante PhD', NULL, 'Florida Tech got caught pushing DEI after Florida law banned it. Charlie Kirk featured this story shortly before he was assassinated. The whistleblower behind the leaked video at Florida Tech was Dr. Rick Addante, a tenured neuroscience professor.
INSERT INTO episodes (title, episode_number, description, guest, duration, publish_date, cloudflare_url, spotify_url, apple_url, youtube_url, rumble_url, tags, featured) VALUES (' THE DREW GRIMALDI PODCAST - SPECIAL GUEST - Ramon Perez', NULL, 'What happens when you mix an artificial intelligence background, military leadership, and a mission to hand political power back to everyday citizens? You get Ramon Perez, Executive Director of the Digital Democracy Project.
