INSERT INTO episodes (title, episode_number, description, guest, duration, publish_date, cloudflare_url, spotify_url, apple_url, youtube_url, rumble_url, tags, featured) VALUES ('THE DREW GRIMALDI PODCAST - SPECIAL GUEST ADAM SWART', 8, 'Adam Swart is the founder of Crowds on Demand, the original paid protesting and advocacy firm, known for organizing high-profile campaigns across the political spectrum. With over a decade of experience in public mobilization, Adam has become one of the nation''s foremost experts on how modern protests are funded, staged, and weaponized for media and political impact. He has been featured on Fox News, Fox Business, NewsNation, and OAN, where his insights have gone viral — drawing millions of views and sparking a national conversation about authenticity and ethics in activism.
